<template>
  <swiper :indicator-dots="true" :autoplay="true" :interval="4000" :circular="true" :style="{height}">
    <swiper-item v-for="(img, i) in images" :key="i">
      <image :src="img" mode="aspectFill" class="hero-image"/>
      <view class="hero-overlay">
        <text class="hero-title">{{titles[i] || ''}}</text>
      </view>
    </swiper-item>
  </swiper>
</template>

<script>
export default {
  name: 'Hero',
  props: {
    images: { type: Array, default: function(){ return [] } },
    titles: { type: Array, default: function(){ return [] } },
    height: { type: String, default: '180px' }
  }
}
</script>

<style scoped>
.hero-image{ width:100%; height:100%; }
.hero-overlay{
  position:absolute; left:0; right:0; bottom:16px; padding:0 16px;
  background: linear-gradient(180deg, rgba(0,0,0,0) 0%, rgba(0,0,0,0.32) 100%);
}
.hero-title{ color:#fff; font-size:18px; font-weight:700; }
</style>